  ('ev-online-android-12-bootcamp-design-for-everyone-begum-yolcu-24c79c84', 'online-android-12-bootcamp-design-for-everyone-begum-yolcu-24c79c84', 'Online | Android 12 Bootcamp | Design for Everyone | Begüm Yolcu', '🚀Android 12 Bootcamp''te son dersimizdeyiz 📚"Design for Everyone" konusunu anlatmak için Begüm Yolcu bizlerle! Bootcamp derslerimizin kalanına buradan…', '🚀Android 12 Bootcamp''te son dersimizdeyiz 📚"Design for Everyone" konusunu anlatmak için Begüm Yolcu bizlerle! Bootcamp derslerimizin kalanına buradan ulaşabilirsiniz ➡️ https://youtube.com/playlist?list=PLZj2Q42tw-6_YwlaPydXHu41zXHV2OHSc', 'events/online-android-12-bootcamp-design-for-everyone-begum-yolcu-24c79c84.png', 'multiacademy', 'bootcamp', 'Online', '', 1, 1645376400, 1645383600, '', 'archive', 'published', 0, 'Android', 1008),
  ('ev-just-coffee-talk-4be1cd2a', 'just-coffee-talk-4be1cd2a', 'Just Coffee & Talk', 'Selam! Havaların da ısınması ile birlikte güzel bir kahve bahanesiyle yeniden bir araya gelmenin tam zamanı! 23 Mayıs Pazartesi günü 18.00''da Kadıköy''de…', 'Selam! Havaların da ısınması ile birlikte güzel bir kahve bahanesiyle yeniden bir araya gelmenin tam zamanı! 23 Mayıs Pazartesi günü 18.00''da Kadıköy''de buluşuyoruz! Mesai sonrası mobil geliştiriciliği ile ilgili keyifli bir sohbete katılmak istersen seni de bekliyoruz! Cafe Voge(Eski Coffeetopia) 4. Kat''ta görüşmek üzere! Kafe Tarif: Kadıköy Boğa heykeli üstü Starbucks karşısı Vogs Kafe. Haritada Coffeetopia olarak gözükebilir.', 'events/just-coffee-talk-4be1cd2a.jpg', 'multigroup', 'meetup', 'Coffeetopia Bahariye', 'İstanbul', 0, 1653318000, 1653328800, '', 'archive', 'published', 0, 'Socialize', 1009);
INSERT OR REPLACE INTO events (id, slug, title, summary, description, cover_image, community, category, location, city, is_online, starts_at, ends_at, registration_url, source, status, is_featured, tags, sort_order) VALUES
  ('ev-google-io-extended-web-edition-4c56483c', 'google-io-extended-web-edition-4c56483c', 'Google IO Extended Web Edition', 'Google I/O Extended eventleri, Google I/O süreci boyunca gerçekleşen önemli gelişmeleri bölgesel organizatörler tarafından tamamiyle türkçe halde erişiminize…', 'Google I/O Extended eventleri, Google I/O süreci boyunca gerçekleşen önemli gelişmeleri bölgesel organizatörler tarafından tamamiyle türkçe halde erişiminize sunmaya odaklanan Etkinliklerdir. Gelin web hakkındaki yenilikleri ne gibi gelişmeler olduğunu birlikte konuşalım. Katılım Şartları Fiziksel olarak katılmak isteyen arkadaşların katılım formunu doldurması ve olumlu katılım sonucunun mail ile tarafına iletilmesi gerekiyor. Fiziksel katılacak arkadaşlar için sağlık tedbiri olarak maske takılması ricamızdır. Etkinlik boyunca içecek ve atıştırmaklık ikramlar olacaktır. Fiziksel katılım için kontenjan 80 kişi ile sınırlıdır. #IOWebExtended Sosyal Medyalarımız Instagram: https://www.instagram.com/devmultigroup/ Twitter: https://twitter.com/devmultigroup Linkedin: https://www.linkedin.com/company/developermultigroup Youtube: https://www.youtube.com/channel/UCLZYXtIvgoJsXG8bL4bx6EA/featured Katılım Formu: https://forms.gle/5TAiigjNL7fsDi827 Canlı Yayın Linki: https://www.youtube.com/watch?v=A-WGqBjg9sA', 'events/google-io-extended-web-edition-4c56483c.png', 'multigroup', 'meetup', 'İBB Zemin İstanbul', 'İstanbul', 0, 1655035200, 1655049600, '', 'archive', 'published', 0, '', 1010),
  ('ev-ml-career-hole-f314d358', 'ml-career-hole-f314d358', 'ML Career Hole', 'ML tutkunları, Developer MultiGroup ve Zemin İstanbul iş birliği ile düzenlenen "ML Career Hole"''de bir araya geliyor. Alanında uzman konuşmacılar ve ilham…', 'ML tutkunları, Developer MultiGroup ve Zemin İstanbul iş birliği ile düzenlenen "ML Career Hole"''de bir araya geliyor. Alanında uzman konuşmacılar ve ilham dolu hikayeler ile keyifli bir etkinlik sizleri bekliyor! Eğer sen de ML alanında kendini geliştiriyor ve uzun bir pandemi sürecinin ardından sahalara dönmenin vakti geldi diyorsan bu etkinlik tam sana göre. Sınırlı katılım ile gerçekleşecek etkinlikte yerini ayırtmayı unutma:) Sosyal Medyalarımız: Instagram Link | Twitter Link | Linkedin Link | Youtube Link | Github Link | Medium Link', 'events/ml-career-hole-f314d358.png', 'multigroup', 'meetup', 'İBB Zemin İstanbul', 'İstanbul', 0, 1661684400, 1661698800, '', 'archive', 'published', 0, '#Career,machine learning', 1011),
  ('ev-gelecek-planlarimiz-f2b9a3e2', 'gelecek-planlarimiz-f2b9a3e2', 'Gelecek Planlarımız #1', 'Sonraki etkinliklerimizin plan aşamasına dahil olmak ister misin? Bildiğiniz üzere 1 ay içerisinde sizleri 2 Harika etkinlikte konuk ettik ve bu harika bir…', 'Sonraki etkinliklerimizin plan aşamasına dahil olmak ister misin? Bildiğiniz üzere 1 ay içerisinde sizleri 2 Harika etkinlikte konuk ettik ve bu harika bir histi. Peki bir sonraki etkinliği kendine uygun hale getirmeye ne dersin? Gelin keyifli bir sohbet eşliğinde Dev MultiGroup kimdir, neden var ve bir sonraki etkinlikte neler olacak birlikte tartışalım. Konuşacağımız Konular: + Starter Bootcampleri: Starter bootcampleri sizi işe sokacak asıl eğitimler öncesi bilmeniz gereken seviyeye getirecek eğitim kamplarıdır. Bir alana yeni geçmeyi planlayanlar için yararlı olacaktır. - Potansiyel Kotlin Starter Camp - Potansiyel Python Starter Camp - Potansiyel C Starter Camp + Main Bootcampler: Bir işe girmenize yardımcı olacak düzeyde eğitim almanızı amaçlayan kamplar, çoğunlukla uygulamaya dayanıklı olacaktır. İş bulma çabasında olanlar için yararlı olacaktır - Potansiyel Android Bootcamp - Potansiyel Jetpack Compose Bootcamp + In-person Etkinlikler: Yüz yüze gerçekleştirmeyi planladığımız gelecek etkinlikler - Potansiyel Angular Day [ İstanbul ] - Potansiyel Mobil Event [ İstanbul ] - Potansiyel Web Summit [ İstanbul ] - Potansiyel MultiCloud Summit [ İstanbul ] Instagram Link | Twitter ', 'events/gelecek-planlarimiz-f2b9a3e2.jpg', 'multiacademy', 'bootcamp', 'Online', '', 1, 1661965200, 1661968800, '', 'archive', 'published', 0, 'morethanamember', 1012),
  ('ev-dunya-yazilim-gelistiricileri-gunu-networking-event-878dbc52', 'dunya-yazilim-gelistiricileri-gunu-networking-event-878dbc52', 'Dünya Yazılım Geliştiricileri Günü Networking Event', 'Dünya Yazılım Geliştiriciler Günü Kutlu Olsun! Developer MultiGroup ve DOP işbirliği ile harika bir kutlama organize ediyoruz. 2019 yılından beri kutlanan…', 'Dünya Yazılım Geliştiriciler Günü Kutlu Olsun! Developer MultiGroup ve DOP işbirliği ile harika bir kutlama organize ediyoruz. 2019 yılından beri kutlanan Dünya Programcılar gününde bir araya geliyoruz. Yazılım geliştiriciler olarak bir araya gelerek network ağımızı genişleteceğimiz, endüstri üzerine keyifli sohbet edeceğimiz bu harika organizasyonda yerini hemen ayırt! 13 Eylül akşamı haberleşmek üzere. Sınırlı katılım ile gerçekleşecek etkinlikte yerini ayırtmayı unutma! Sınırlı katılım ile gerçekleşecek etkinlikte yerini ayırtmayı unutma! Instagram Link | Twitter Link | Linkedin Link | Youtube Link | Github Link | Medium Link', 'events/dunya-yazilim-gelistiricileri-gunu-networking-event-878dbc52.jpg', 'multigroup', 'meetup', 'DOP İnovasyon Merkezi', 'İstanbul', 0, 1663084800, 1663092000, '', 'archive', 'published', 0, 'networking,party', 1013),
  ('ev-angular-day-71cf4af5', 'angular-day-71cf4af5', 'Angular Day', 'Developer MultiGroup, Angular Turkey ve Zemin İstanbul iş birliği ve DOP Inc sponsorluğu ile düzenlenen "Angular Day" ile karşınızdayız! Her geçen gün gelişen…', 'Developer MultiGroup, Angular Turkey ve Zemin İstanbul iş birliği ve DOP Inc sponsorluğu ile düzenlenen "Angular Day" ile karşınızdayız! Her geçen gün gelişen Angular teknolojisi ile web tutkunlarını bir araya getiren Angular Day, sürpriz konuşmacıları ile sizi bekliyor. İlham dolu oturumlar ve network ağınızı genişletebileceğiniz misafirlerimizin olacağı bu etkinliği kaçırmayın. Sınırlı katılım ile gerçekleşecek etkinlikte yerini ayırtmayı unutma! Instagram Link | Twitter Link | Linkedin Link | Youtube Link | Github Link | Medium Link', 'events/angular-day-71cf4af5.png', 'multigroup', 'workshop', 'İBB Zemin İstanbul', 'İstanbul', 0, 1664017200, 1664031600, '', 'archive', 'published', 0, 'angular', 1014),
  ('ev-more-awareness-successful-careers-06756356', 'more-awareness-successful-careers-06756356', 'More Awareness & Successful Careers', 'Başarılı bir kariyer haritası oluşturmak için nerden başlamak gerekiyor? Peki işe girmek kariyerimizin geri kalanı için yeterli mi? Sonrasında neler yapmak…', 'Başarılı bir kariyer haritası oluşturmak için nerden başlamak gerekiyor? Peki işe girmek kariyerimizin geri kalanı için yeterli mi? Sonrasında neler yapmak gerekiyor? Kişisel farkındalığımızı arttıracağımız, sektörel cinsiyet eşitliğine değineceğimiz ve bütün bu soruların cevaplarını birlikte arayacağımız harika bir etkinlik ile sizlerleyiz. İletişim ve sosyal becerilerimiz ile birlikte network ağımızı genişleteceğimiz bu etkinliği kaçırmayın!', 'events/more-awareness-successful-careers-06756356.png', 'multigroup', 'meetup', 'İBB Zemin İstanbul', 'İstanbul', 0, 1664704800, 1664719200, '', 'archive', 'published', 0, '', 1015),
  ('ev-morethan101-a-brief-introduction-to-autoencoders-2f55a6fa', 'morethan101-a-brief-introduction-to-autoencoders-2f55a6fa', '#MoreThan101 | A Brief Introduction to Autoencoders', '#MoreThan101 workshop serisi ile bilgisayarlı görüden doğal dil işlemeye kadar çok şey öğrenip kodlayabilecek, her türlü veri üzerinde çok fazla deneyim…', '#MoreThan101 workshop serisi ile bilgisayarlı görüden doğal dil işlemeye kadar çok şey öğrenip kodlayabilecek, her türlü veri üzerinde çok fazla deneyim kazanabileceksiniz. Kadınların bilgi ve kodlama deneyimleri ile teknoloji alanındaki yetkinliğini artırmayı hedeflediğimiz bu workshoplara katılım sınırlıdır. #MoreThan101 workshop serisi Developer MultiGroup ve Zemin İstanbul partnerliğinde gerçekleşmeye devam ediyor! 9 Ekim Pazar günü saat 14.00''da Zemin İstanbul''da ikincisi gerçekleşecek. Sarper Yurtseven ''A Brief Introduction to Autoencoders'' konusu ile bol teorili ve kodlu bir session için pazar günü aramızda olacak. Sen de formdaki soruları cevaplayarak workshopa katılmaya haz kazan. Unutma, katılım sınırlı. Not: Her workshop kendi başvuru süreci olacaktır.', 'events/morethan101-a-brief-introduction-to-autoencoders-2f55a6fa.jpg', 'multigroup', 'workshop', 'İBB Zemin İstanbul', 'İstanbul', 0, 1665320400, 1665331200, '', 'archive', 'published', 0, '', 1016),
  ('ev-webfree-22-bbf9fc9f', 'webfree-22-bbf9fc9f', 'WebFree 22', 'WebFree ile dolu dolu bir içerik ve sektörün yıldızları ile bir araya gelmeye hazır mısın? 12 Kasım''da Developer MultiGroup ve Zemin İstanbul iş birliği ile…', 'WebFree ile dolu dolu bir içerik ve sektörün yıldızları ile bir araya gelmeye hazır mısın? 12 Kasım''da Developer MultiGroup ve Zemin İstanbul iş birliği ile düzenlenen "WebFree 22" etkinliğinde buluşuyoruz. İlham dolu hikayeler ve yoğun teknik sunumlar eşliğinde keyifli bir etkinlik sizleri bekliyor! Eğer sen de Web alanında kendini geliştiriyor ve network ağını genişletmek istiyorsan bu etkinlik tam sana göre. Sınırlı katılım ile gerçekleşecek etkinlikte yerini ayırtmayı unutma 🙂', 'events/webfree-22-bbf9fc9f.png', 'multigroup', 'meetup', 'İBB Zemin İstanbul', 'İstanbul', 0, 1668247200, 1668261600, '', 'archive', 'published', 0, 'web development,Backend,frontend', 1017),
  ('ev-morethan101-latest-trends-on-language-modeling-safak-bilici-c4b4b0d4', 'morethan101-latest-trends-on-language-modeling-safak-bilici-c4b4b0d4', '#MoreThan101 | Latest Trends on Language Modeling - Şafak Bilici', 'Herkese selamlar 👋🏽 NOT: Katılımcılar bu formdaki soruların cevaplarına göre seçilecektir. Linkte verilen formu doldurunuz. Developer MultiGroup ve Zemin…', 'Herkese selamlar 👋🏽 NOT: Katılımcılar bu formdaki soruların cevaplarına göre seçilecektir. Linkte verilen formu doldurunuz. Developer MultiGroup ve Zemin İstanbul işbirliğinde gerçekleşen #MoreThan101 workshop serimize kaldığımız yerden dördüncüsü ile devam ediyoruz 🎃 Son eğitimimize olan ilginiz için teşekkür ederiz. Sizlerle yeniden görüşmek için sabırsızlanıyoruz 🙆🏽‍♀️ 13 Kasım Pazar günü saat 14.00’da Zemin İstanbul’da, Huawei’de Research Engineer olan Şafak Bilici ile olacağız. “Latest Trends on Language Modeling” isimli doğal dil işlemeye giriş eğitimi ile bizimle olacak. Bu ders Dil Modelleme ile ilgili en son araştırmaları tanıtmayı amaçlamaktadır: mimari tasarımlar, verisetleri, pre-training objectifleri, few/zero-shot özellikleri, çok dillilik, gerçek hayat uygulamaları vb. Eğer siz de bu konularla ilgileniyor ve teknik olarak da deneyimlemek istiyorsanız başvuru formundaki soruları doğru bir şekilde doldurmayı unutmayın ve pazar günü bizlerle olma şansı yakalayın. 🤗 👉🏽 Formu doldurmak için tık tık.', 'events/morethan101-latest-trends-on-language-modeling-safak-bilici-c4b4b0d4.png', 'multigroup', 'workshop', 'İBB Zemin İstanbul', 'İstanbul', 0, 1668337200, 1668351600, '', 'archive', 'published', 0, 'Machine Leaerning,data analysis,natural language processing,nlp,computer vision,Python,python', 1018),
  ('ev-morethan101-data-to-text-generation-via-seq2seq-networks-seniz-demir-fc3e4cef', 'morethan101-data-to-text-generation-via-seq2seq-networks-seniz-demir-fc3e4cef', '#MoreThan101 | Data-to-Text Generation via Seq2Seq Networks - Şeniz Demir', 'Herkese selamlar 👋 NOT: Katılımcılar bu formdaki soruların cevaplarına göre seçilecektir. Linkte verilen formu doldurunuz. Formu doldurmayanların başvuruları…', 'Herkese selamlar 👋 NOT: Katılımcılar bu formdaki soruların cevaplarına göre seçilecektir. Linkte verilen formu doldurunuz. Formu doldurmayanların başvuruları kabul edilmeyecektir. Hız kesmeden Developer MultiGroup ve Zemin İstanbul işbirliği ile düzenlenen #MoreThan101 workshop serimize beşincisi ile devam ediyoruz. 26 Kasım Cumartesi günü saat 14.00’da MEF Üniversitesi’nde Doktor Öğretim Üyesi olan çok sevgili Şeniz Demir ile birlikte olacağız. Kendisi ‘ Data-to-Text Generation via Seq2Seq Networks’ konulu eğitimi ile sizlere doğal dil işleme problemlerinden biri olan metin üretimi hakkında bilgiler verecek. Yine bol teorili ve uygulamalı bir eğitim siz katılımcılarımızı bekliyor. Her zamanki gibi formdaki soruları doğru cevaplayarak eğitime katılmaya hak kazanın 👊 Sizlerle tanışmak için sabırsızlanıyoruz! FORM LİNKİ -&gt; https://forms.gle/ZCamQG5bEjf2HuJy9', 'events/morethan101-data-to-text-generation-via-seq2seq-networks-seniz-demir-fc3e4cef.png', 'multigroup', 'workshop', 'İBB Zemin İstanbul', 'İstanbul', 0, 1669460400, 1669473000, '', 'archive', 'published', 0, 'Machine Leaerning,Python,natural language processing,computer vision,Artificial intelligence,istanbul workshop,python workshop', 1019);
INSERT OR REPLACE INTO events (id, slug, title, summary, description, cover_image, community, category, location, city, is_online, starts_at, ends_at, registration_url, source, status, is_featured, tags, sort_order) VALUES
  ('ev-iamremarkable-workshop-series-1-5404007a', 'iamremarkable-workshop-series-1-5404007a', '#IamRemarkable Workshop Series #1', 'Herkese selamlar 👋🏼 #IamRemarkable workshop ile kişisel farkındalıklarımızı arttırıp, başarılarımıza ses veriyoruz! Eğer siz de kendinizin ya da başkalarının…', 'Herkese selamlar 👋🏼 #IamRemarkable workshop ile kişisel farkındalıklarımızı arttırıp, başarılarımıza ses veriyoruz! Eğer siz de kendinizin ya da başkalarının karşılaştığı zorlukları daha iyi anlamak ve mevcut önyargılara meydan okumaya yardımcı olmak istiyorsanız 8 Aralık’ta bize katılın. Güldeniz Bektaş ve Ceren Tunay tarafından gerçekleştirilecek olan #IamRemarkable online workshopı kapalı oturum olarak gerçekleşecektir. Bu yüzden katılmak için formu doldurmayı unutmayın 😎', 'events/iamremarkable-workshop-series-1-5404007a.jpg', 'multigroup', 'workshop', 'Online', '', 1, 1670518800, 1670522400, '', 'archive', 'published', 0, '', 1020),
  ('ev-morethan101-computer-vision-problems-and-overview-of-different-approaches-594a9337', 'morethan101-computer-vision-problems-and-overview-of-different-approaches-594a9337', '#MoreThan101 | Computer Vision Problems and Overview of Different Approaches', 'Herkese selamlar! Akbank ile sizlere süper bir haberimiz var! Artık Developer MultiGroup ve Akbank işbirliğinde gerçekleşecek #MoreThan101 workshop serimize…', 'Herkese selamlar! Akbank ile sizlere süper bir haberimiz var! Artık Developer MultiGroup ve Akbank işbirliğinde gerçekleşecek #MoreThan101 workshop serimize altıncısı ile devam ediyoruz. Bu haberi sizlerle paylaştığımız için çok mutluyuz. Huawei’de Research Engineer olarak çalışan Enes Sadi Uysal 24 Aralık Cumartesi günü saat 15.00’da Network Academy Kadıköy’de, “Computer Vision Problems and Overview of Different Approaches” konusu ile bizlerle olacak. Enes Sadi, Yıldız Teknik Üniversitesi Bilgisayar Mühendisliği lisans programından 2022 yılında mezun oldu. Şu anda YTÜ''de Bilgisayar Mühendisliği Yüksek Lisans öğrencisiyi. Aynı zamanda Huawei R&D şirketinde Research Engineer olarak çalışıyor. Yaklaşık 3 yıldır Derin Öğrenme ve Computer Vision ile ilgilenmekte. Eğer sizde bilgisayarlı görü ile ilgileniyor ve daha fazlasını öğrenmek istiyorsanız formu doldurarak katılma şansı yakalamayı unutmayın. Form için → https://forms.gle/mtvyhh5vtc3X1Pbk9', 'events/morethan101-computer-vision-problems-and-overview-of-different-approaches-594a9337.png', 'multiacademy', 'workshop', 'Network Academy', 'İstanbul', 0, 1671883200, 1671890400, '', 'archive', 'published', 0, '#morethan101', 1021),
  ('ev-web3-developer-summit-abb9d0ce', 'web3-developer-summit-abb9d0ce', 'Web3 Developer Summit', 'Ayrıntılar: Etkinlik kaydını tamamlamak için lütfen web sitemizi ziyaret ediniz: https://web3devsummit.istanbul Web3 ekosisteminin geliştirici, tasarımcı ve…', 'Ayrıntılar: Etkinlik kaydını tamamlamak için lütfen web sitemizi ziyaret ediniz: https://web3devsummit.istanbul Web3 ekosisteminin geliştirici, tasarımcı ve proje üreten paydaşları "deneyim paylaşımı" ana teması ile bir araya geliyor Kimin için ne var? Developerlar Yeni geliştirme araçlarını tanıma Blockchain ağlarının detaylarına hızlı bir bakış Web3 proje yönetim süreçlerini anlama Oyun ekosistemi Oyun içi yeni ekonomi modellerini tanıma Blockchain üzerinde oyun geliştiren stüdyolar ile tanışma Kariyer ve network imkanı Yenilikçi firmalar Web3 dünyasındaki yeni fırsatlar Değişen marketing kuralları Yeni müşteri eğilimlerini görme Venture CapItal ''ler Yetenek havuzuna ulaşma Network imkanı Projelere doğrudan erişim Hedef Kitle Developer''lar: Developerlar için yeni bir dünyanın kapıları aralanıyor. Web3 geliştirici ekosistemindeki tüm araç ve gereçler, internetin değişen tanımı ve bu tanıma göre ortaya çıkan yeni kodlama teknolojileri... Panel ve workshoplardan oluşan dolu dolu içerik. Blockchain ekosistemindeki oyun ve projelerin deneyimlerini doğrudan dinleme imkanı. Oyun Ekosistemi: "Sonraki 1 Milyon Web3 kullanıcısı oyun sektöründen gelecek" - Paydaşların dünyanın en uzak köşes', 'events/web3-developer-summit-abb9d0ce.png', 'multigroup', 'summit', 'Istanbul Kültür University', 'İstanbul', 0, 1673071200, 1673100000, '', 'archive', 'published', 0, 'Web3', 1022),
  ('ev-morethan101-7-tensorflow-102-guldeniz-bektas-8324afc1', 'morethan101-7-tensorflow-102-guldeniz-bektas-8324afc1', '#MoreThan101 #7 | Tensorflow 102 - Güldeniz Bektaş', 'NOT: Etkinliğimiz için form doldurulması zorunludur. Forma buradan ulaşabilirsiniz. Herkese selamlar 👋 Akbank işbirliği ile düzenlediğimiz #MoreThan101…', 'NOT: Etkinliğimiz için form doldurulması zorunludur. Forma buradan ulaşabilirsiniz. Herkese selamlar 👋 Akbank işbirliği ile düzenlediğimiz #MoreThan101 workshop serimizin yedincisi geliyor. 8 Ocak Pazar günü, 2023’ün ilk etkinliğinde, workshop düzenleyicimiz Güldeniz Bektaş bizlerle olacak. “Tensorflow 102” konulu eğitimi ile Tensorflow ile model eğitimi ve geliştirmesi üzerine bir workshop gerçekleştireceğiz. 🚀 Güldeniz, İstanbul Üniversitesi Astronomi ve Uzay bilimleri bölümü mezunu. Şu an da Denebunu şirketinde Data Scientist olarak çalışan Güldeniz yakın zamada Tensorflow Developer Certificate aldı. Topluluklarda eğitim veriyor ve konuşmalar yapıyor ve aynı zamanda "Yapay mı Bu Zeka?" isimli bir podcasti var. Özel olarak computer vision ile ilgileniyor. 🤖 Tensorflow 102 eğitimi ile Tensorflow ile Computer Vision modeli nasıl oluşturulabilir, hangi yöntemler ile doğruluk oranı nasıl arttırılabilir gördükten sonra, transfer learning ile nasıl daha az veri ile güzel sonuçlara ulaşabiliriz onu göreceğiz.🤩 Görüşmek üzere 🙌', 'events/morethan101-7-tensorflow-102-guldeniz-bektas-8324afc1.png', 'multiacademy', 'workshop', 'Network Academy', 'İstanbul', 0, 1673179200, 1673186400, '', 'archive', 'published', 0, 'MachineLearning,DataScience,tensorflow', 1023),
  ('ev-sohbetmuhabbet-ilginc-hikayeler-ile-farkli-bir-seri-basliyor-522ecf22', 'sohbetmuhabbet-ilginc-hikayeler-ile-farkli-bir-seri-basliyor-522ecf22', '#SohbetMuhabbet | İlginç Hikayeler İle Farklı Bir Seri Başlıyor!', 'Yeni serimiz Sohbet Muhabbet, sizleri çayınızı kahvenizi kapıp, kafa dağıtacak güzel bir sohbete katılmaya davet ediyor Teknik veya bilgilendirme…', 'Yeni serimiz Sohbet Muhabbet, sizleri çayınızı kahvenizi kapıp, kafa dağıtacak güzel bir sohbete katılmaya davet ediyor Teknik veya bilgilendirme oturumlarından sıkılmış, kafasını dağıtmak isteyen developerlar için online bir sohbet ortamı olmayı amaçlıyor. Bu yayınlarda herhangi bir hatayı nasıl çözeceğinizi konuşmaktansa; Yazılım sektöründeki komik olayları, Bizlerin başına gelmiş ilginç anıları veya o an vizyona girmiş güzel bir filmi konuşup kafanızı dağıtmak ve keyifli vakit geçirmenizi sağlamak çok isteriz! Kasım Adalan ve Serkan Alc ikilisi ile gerçekleşecek bu yayın serisi, ara ara katılacak sürpriz konukları ve ilginç hikayeleri ile sizleri sadece bir izleyici değil o sohbetin içindeki bir konuk olmaya davet ediyor. Sizin katılımınız eminiz ki bu sohbeti daha eğlenceli hale getirecektir. Instagram Link | Twitter Link | Linkedin Link | Youtube Link | Github Link | Medium Link', 'events/sohbetmuhabbet-ilginc-hikayeler-ile-farkli-bir-seri-basliyor-522ecf22.png', 'multigroup', 'meetup', 'Online', '', 1, 1674064800, 1674072000, '', 'archive', 'published', 0, '', 1024),
  ('ev-izel-yazici-ozcan-feature-engineering-in-automotive-industry-january-21-91331831', 'izel-yazici-ozcan-feature-engineering-in-automotive-industry-january-21-91331831', 'İzel Yazıcı Özcan - Feature Engineering in Automotive Industry | January 21', 'Katılım için form doldurmak zorunludur. Herkese selamlar 👋 Akbank işbirliği ile düzenlediğimiz #MoreThan101 workshop serimizin sekizincisi geliyor. 21 Ocak…', 'Katılım için form doldurmak zorunludur. Herkese selamlar 👋 Akbank işbirliği ile düzenlediğimiz #MoreThan101 workshop serimizin sekizincisi geliyor. 21 Ocak Cumartesi günü online gerçekleşecek workshopımızda İzel Yazıcı Özcan bizlerle olacak. “Feature Engineering in Automotive Industry” konulu eğitimi ile anlatıcımız olacak 🚀 İzel Yazıcı Özcan 2018 Marmara Endüstri Mühendisliği bölümün mezun oldu. Öğrencilik yıllarında katılmış olduğu staj deneyimleri ile Veri Bilimi alanına yöneldi. Profesyonel hayatına Veri Bilimi üzerine kurumsal firmalara danışmanlık veren, bir danışmanlık firması olan Analythinx''te başladı. 2 yıl boyunca 5 farklı firmaya danışmanlık verdi. 2021 yılında kurumsal hayat deneyimi için, Koç grubu bünyesindeki Otokoç Otomotiv''de Veri Bilimci olarak çalışmaya başladı. Burada yeni kurulan analitik ekip''in AnalyticsOps süreçlerini ve Analitik projelerini yönetti. 2022 Haziran ayında Koç Üniversitesi Veri Bilimi yüksek lisansından mezun oldu. Eğitim içeriğimiz case study üzerinden anlatımlarla ilerleyecek ve İzel bizlere Azure ile analitik proje mimarisini baştan uca nasıl müşterilere sunduklarını, deployement vb. süreçleri bizlere anlatacak. Görüşmek üzere 🙌 Form içi', 'events/izel-yazici-ozcan-feature-engineering-in-automotive-industry-january-21-91331831.png', 'multigroup', 'meetup', 'Online', '', 1, 1674302400, 1674309600, '', 'archive', 'published', 0, 'data science,Machine Learning,deep learning', 1025),
  ('ev-sohbet-muhabbet-2-sektorden-haberler-ve-daha-fazlasi-8af2a72e', 'sohbet-muhabbet-2-sektorden-haberler-ve-daha-fazlasi-8af2a72e', 'Sohbet Muhabbet #2 | Sektörden Haberler Ve Daha Fazlası', 'Sohbet Muhabbet 2. Bölümü ile sezleri Sektöre dair haberler ve yorumlamalara davet ediyor. Teknik veya bilgilendirme oturumlarından sıkılmış, kafasını dağıtmak…', 'Sohbet Muhabbet 2. Bölümü ile sezleri Sektöre dair haberler ve yorumlamalara davet ediyor. Teknik veya bilgilendirme oturumlarından sıkılmış, kafasını dağıtmak isteyen developerlar için online bir sohbet ortamı olmayı amaçlayan Sohbet Muhabbet, Bu bölümünde sizleri sektörde olan bitenler ve yaşanan olayları başka bir pencereden gösterecek. Sohbet böyle başlasa da kim bilir muhabbet nerde sonlanacak! Kasım Adalan ve Serkan Alc ikilisi ile gerçekleşecek bu yayın serisi, ara ara katılacak sürpriz konukları ve ilginç hikayeleri ile sizleri sadece bir izleyici değil o sohbetin içindeki bir konuk olmaya davet ediyor. Sizin katılımınız eminiz ki bu sohbeti daha eğlenceli hale getirecektir. Youtube Kanalımıza abone olmayı unutmayın!', 'events/sohbet-muhabbet-2-sektorden-haberler-ve-daha-fazlasi-8af2a72e.png', 'multigroup', 'meetup', 'Online', '', 1, 1674842400, 1674846000, '', 'archive', 'published', 0, '#sohbetmuhabbet', 1026),
  ('ev-sohbet-muhabbet-3-sektore-girmeden-once-33a19c34', 'sohbet-muhabbet-3-sektore-girmeden-once-33a19c34', 'Sohbet Muhabbet 3 | Sektöre Girmeden Önce...', 'Sohbet Muhabbet 3', 'Sohbet Muhabbet 3', 'events/sohbet-muhabbet-3-sektore-girmeden-once-33a19c34.png', 'multigroup', 'meetup', 'Online', '', 1, 1676052000, 1676059200, '', 'archive', 'published', 0, '', 1027),
  ('ev-morethan101-10-muhammet-nusret-ozates-5d38ae83', 'morethan101-10-muhammet-nusret-ozates-5d38ae83', '#MoreThan101 #10 | Muhammet Nusret Özateş', 'Herkese merhaba! Developer MultiGroup olarak Akbank işbirliği ile düzenlediğimiz #MoreThan101 serimizin onuncusu ile on-site olarak sizlerleyiz. İlgi çekici…', 'Herkese merhaba! Developer MultiGroup olarak Akbank işbirliği ile düzenlediğimiz #MoreThan101 serimizin onuncusu ile on-site olarak sizlerleyiz. İlgi çekici bir konu ve sürpriz hediyeler #MoreThan101 ile sizleri bekliyor. Onuncu eğitimimiz 18 Mart’ta Sabancı Center''da gerçekleşecek. 18 Mart Cumartesi günü saat 12’de Muhammet Nusret Özateş ‘MLOps: Experiment Tracking and Automatization’ isimli eğitimi ile bizlerle olacak. Muhammet Nusret Özateş şu anda Koç Üniversitesi''nde yüksek lisans yaparken TRT''de NLP ve MLOps alanlarında Machine Learning Engineer olarak çalışıyor. 2023''te Google Cloud - Professional Machine Learning Engineer sertifikasını kazandı. Veri bilimi topluluğuna katkıda bulunmak için öğrendiklerini Medium''da ve youtube canlı yayınları aracılığı ile düzenli olarak paylaşıyor. Bu workshop ile MLOps''un tanımından başlayıp, duration prediction örneği üzerinden MLFlow ile experiment tracking konusunu anlatıp sonrasında da zararlı içerik tespiti örneği üzerinden Prefect ile data ve training pipeline oluşturma konularını uygulayarak göreceğiz. Sizler de bizimle orada olmak için formu doldurmayı unutmayın. https://forms.gle/v3b87prrTF4Q85tB6 Görüşmek üzere!', 'events/morethan101-10-muhammet-nusret-ozates-5d38ae83.png', 'multigroup', 'workshop', 'Akbank', 'İstanbul', 0, 1679130000, 1679142600, '', 'archive', 'published', 0, '', 1028),
  ('ev-sohbet-muhabbet-3-sektor-oncesi-deneyim-1c7b8eb2', 'sohbet-muhabbet-3-sektor-oncesi-deneyim-1c7b8eb2', 'Sohbet Muhabbet 3 | Sektör Öncesi Deneyim!', 'Sohbet Muhabbet 3. Bölümü sizleri Sektöre öncesi deneyim edinebilme yolları ve sektöre hazır bir şekilde nasıl ilerlenebileceği hakkında sıcak bir sohbete…', 'Sohbet Muhabbet 3. Bölümü sizleri Sektöre öncesi deneyim edinebilme yolları ve sektöre hazır bir şekilde nasıl ilerlenebileceği hakkında sıcak bir sohbete davet ediyor. Teknik veya bilgilendirme oturumlarından sıkılmış, kafasını dağıtmak isteyen developerlar için online bir sohbet ortamı olmayı amaçlayan Sohbet Muhabbet, Bu bölümünde sizleri sektöre girmeden önce yapılması mantıklı olan davranışları veya alışkanlıkları, moderatörlerinin yorumlarını da işin içine katarak muhabbet tadında sizlere sunmayı planlıyor. Kasım Adalan ve Serkan Alc ikilisi ile gerçekleşecek bu yayın serisi, ara ara katılacak sürpriz konukları ve ilginç hikayeleri ile sizleri sadece bir izleyici değil o sohbetin içindeki bir konuk olmaya davet ediyor. Sizin katılımınız eminiz ki bu sohbeti daha eğlenceli hale getirecektir. Youtube Kanalımıza abone olmayı unutmayın!', 'events/sohbet-muhabbet-3-sektor-oncesi-deneyim-1c7b8eb2.png', 'multigroup', 'meetup', 'Online', '', 1, 1679684400, 1679688000, '', 'archive', 'published', 0, '', 1029);
INSERT OR REPLACE INTO events (id, slug, title, summary, description, cover_image, community, category, location, city, is_online, starts_at, ends_at, registration_url, source, status, is_featured, tags, sort_order) VALUES
  ('ev-sohbet-muhabbet-4-sadece-kod-yazmak-yeter-mi-e0120b39', 'sohbet-muhabbet-4-sadece-kod-yazmak-yeter-mi-e0120b39', 'Sohbet Muhabbet 4 | Sadece Kod Yazmak Yeterli Mi?', 'Sohbet Muhabbet 4. Bölümü ile sizleri Sadece Kod Yazmak Yeter mi? sorusu ile karşılıyor! Bu bölümünde sizlerle iyi kod yazmak dışında hangi yeteneklere sahip…', 'Sohbet Muhabbet 4. Bölümü ile sizleri Sadece Kod Yazmak Yeter mi? sorusu ile karşılıyor! Bu bölümünde sizlerle iyi kod yazmak dışında hangi yeteneklere sahip olunması gerektiği ve bunları nasıl sektörde aktif kullanılabileceği hakkında bir sohbete davet ediyoruz. Gerek hoş sohbet gerekse ilginç ve dallanacak konular ile bu haftaki bölüm bizi oldukça heyecanlandırıyor. Kaçırmayın! Ve hatırlatmakta fayda var youtube kanalımıza abone olmayı lütfen unutmayın!', 'events/sohbet-muhabbet-4-sadece-kod-yazmak-yeter-mi-e0120b39.png', 'multigroup', 'meetup', 'Online', '', 1, 1680894000, 1680897600, '', 'archive', 'published', 0, '', 1030),
  ('ev-sohbet-muhabbet-5-d9e71dab', 'sohbet-muhabbet-5-d9e71dab', 'Sohbet Muhabbet 5', 'Teknik veya bilgilendirme oturumlarından sıkılmış, kafasını dağıtmak isteyen developerlar için online bir sohbet ortamı olmayı amaçlayan Sohbet Muhabbet, Bu…', 'Teknik veya bilgilendirme oturumlarından sıkılmış, kafasını dağıtmak isteyen developerlar için online bir sohbet ortamı olmayı amaçlayan Sohbet Muhabbet, Bu bölümünde sizleri sektöre girmeden önce yapılması mantıklı olan davranışları veya alışkanlıkları, moderatörlerinin yorumlarını da işin içine katarak muhabbet tadında sizlere sunmayı planlıyor. Kasım Adalan ve Serkan Alc ikilisi ile gerçekleşecek bu yayın serisi, ara ara katılacak sürpriz konukları ve ilginç hikayeleri ile sizleri sadece bir izleyici değil o sohbetin içindeki bir konuk olmaya davet ediyor. Sizin katılımınız eminiz ki bu sohbeti daha eğlenceli hale getirecektir. Youtube Kanalımıza abone olmayı unutmayın!', 'events/sohbet-muhabbet-5-d9e71dab.png', 'multigroup', 'meetup', 'Online', '', 1, 1681498800, 1681502400, '', 'archive', 'published', 0, '', 1031),
  ('ev-disconnect-25a43815', 'disconnect-25a43815', 'Disconnect!', 'Hey Oyun Geliştiriciler! Sizi heyecan verici bir etkinliğe davet etmekten mutluluk duyuyoruz! Bilgisayarlarınızdan biraz uzaklaşıp, ağınızı genişletmek, bilgi…', 'Hey Oyun Geliştiriciler! Sizi heyecan verici bir etkinliğe davet etmekten mutluluk duyuyoruz! Bilgisayarlarınızdan biraz uzaklaşıp, ağınızı genişletmek, bilgi paylaşımı yapmak ve sektördeki diğer yeteneklerle bağlantı kurmak için mükemmel bir fırsat sizleri bekliyor. Dev MultiGroup, oyun geliştiricilerin güçlü bir ağ oluşturmasını ve karşılıklı öğrenmeyi desteklemeyi hedefleyen bir etkinlik sizleri karşılıyor. Bu etkinlikte, sektörün önde gelen isimleriyle tanışacak, deneyimlerini paylaşacak ve yaratıcılığınızı bir adım öteye taşıyacak fikirler edineceksiniz. Bu etkinliğe katılım, oyun geliştirme kariyerinizi ilerletmek ve sektördeki diğer yeteneklerle bağlantı kurmak için mükemmel bir fırsat sunuyor. Ağınızı genişletmek, yeni bilgiler edinmek ve ilham almak için hazır olun! Etkinlikle ilgili sorularınız veya daha fazla bilgi için bize ulaşmaktan çekinmeyin Instagram Link | Twitter Link | Linkedin Link | Youtube Link | Github Link | Medium Link', 'events/disconnect-25a43815.png', 'multigroup', 'meetup', 'Facebook İstasyon', 'İstanbul', 0, 1688900400, 1688914800, '', 'archive', 'published', 0, '', 1032),
  ('ev-data-science-meetup-f379de30', 'data-science-meetup-f379de30', 'Data Science Meetup', 'Data Science Meetup Sizlerle! 🙌 Tüm veri bilimi meraklılarına sesleniyoruz! Veri bilimi dünyasını keşfedeceğiniz heyecan verici bir buluşma etkinliği için…', 'Data Science Meetup Sizlerle! 🙌 Tüm veri bilimi meraklılarına sesleniyoruz! Veri bilimi dünyasını keşfedeceğiniz heyecan verici bir buluşma etkinliği için bize katılmaya ne dersiniz? 📌 Sizler gibi Veri bilimi meraklıları ile bağlantı kurmak, deneyimlerinizi paylaşmak ve sektörü şekillendiren en son trendler ve tekniklerin derinliklerine dalmak sizlerin elinde. İster tecrübeli bir veri bilimcisi olun ister meraklı bir acemi veya sadece veri konusunda tutkulu, bu etkinlik tam size göre. Networkünüzü geliştirmek, öğrenmek ve ilham almak için bu fırsatı kaçırmayın! Şimdi biletinizi alın ve etkinliğin bir parçası olun!" Etkinliğimizde sizleri neler bekliyor: ✨ Alanında başarılı kişilerle tanışma şansı 🧩 Network''ünüzü geliştirmek için türlü etkinlikler. 🍕 Yiyecek içecek ikramı. 🎁 Sürpriz hediye ve çekilişler. 👀 Unutmayın! Community Supporter Ticket alarak bu tarz etkinlikleri geliştirmemizde yardımcı olabilir ve community supporter özel avantajlarından yararlanabilirsiniz! Etkinlik görsellerini bu linkte bulabilirsiniz: https://drive.google.com/drive/folders/1f4eZcE3vcqSH0aD9B2xR_hFcHUXYo663?usp=drive_link', 'events/data-science-meetup-f379de30.png', 'multigroup', 'meetup', 'Facebook İstasyon', 'İstanbul', 0, 1692529200, 1692543600, '', 'archive', 'published', 0, '#datascience,#machinelearning,#meetup,RPA', 1033),
  ('ev-dunya-yazilim-gelistiriciler-gunu-networking-event-c774391a', 'dunya-yazilim-gelistiriciler-gunu-networking-event-c774391a', 'Dünya Yazılım Geliştiriciler Günü Networking Event', 'After Global Developer Day 23 Sizlerle! 📢 Her sene gerçekleştirdiğimiz gibi bu sene de küçük bir gecikmeyle birlikte dünya yazılım geliştiriciler gününde…', 'After Global Developer Day 23 Sizlerle! 📢 Her sene gerçekleştirdiğimiz gibi bu sene de küçük bir gecikmeyle birlikte dünya yazılım geliştiriciler gününde sizlerleyiz. 📌 Sizler gibi yazılım geliştiriciliğine merak duyanlar ile bağlantı kurmak, deneyimlerinizi paylaşmak ve sektörü şekillendiren en son trendler ve tekniklerin derinliklerine dalmak sizlerin elinde. İster tecrübeli bir developer olun ister meraklı bir acemi veya sadece yazılım konusunda tutkulu, bu etkinlik tam size göre. Networkünüzü geliştirmek, öğrenmek ve ilham almak için bu fırsatı kaçırmayın! Şimdi biletinizi alın ve etkinliğin bir parçası olun!" Etkinliğimizde sizleri neler bekliyor: 🧩 Network''ünüzü geliştirmek için türlü etkinlikler. 🍕 Yiyecek içecek ikramı. 🎁 Sürpriz hediye ve çekilişler. 👀 Unutmayın! Community Supporter Ticket alarak bu tarz etkinlikleri geliştirmemizde yardımcı olabilir ve community supporter özel avantajlarından yararlanabilirsiniz! ❗️ Community Supporter biletleri etkinlik alanı için bir ayrıcalık tanımayacaktır, bizi desteklemek ve birsonraki etkinliği geliştirmemize yardımcı olmak isteyen kişiler için uygundur!', 'events/dunya-yazilim-gelistiriciler-gunu-networking-event-c774391a.png', 'multigroup', 'meetup', 'Snow Consulting Eğitim. Turizm Tic. Ltd. Şti.', 'İstanbul', 0, 1694793600, 1694804400, '', 'archive', 'published', 0, '', 1034),
  ('ev-dmg-coffee-talk-c0769d51', 'dmg-coffee-talk-c0769d51', 'DMG Coffee Talk', 'Bir Kahve Molasına Ne Dersin? 📢 Uzun zamandır etkinliklerimize katılıyorsunuz ve yarı yarıya tanıştık sayılır. Peki güzel bir kahve eşliğinde bu tanışmışlığı…', 'Bir Kahve Molasına Ne Dersin? 📢 Uzun zamandır etkinliklerimize katılıyorsunuz ve yarı yarıya tanıştık sayılır. Peki güzel bir kahve eşliğinde bu tanışmışlığı tamamlamaya ne dersiniz? Bunun yanı sıra: 📌 Biliyoruz ki; kodlar, algoritma problemleri ve sıfırlarla birler arasındaki o sınırsız evrende senin için birçok şeyi ifade ediyor. Ancak tüm bu karmaşık dünyada bazen bir kahve molası, bir sohbet ya da biraz ilham alacak bir konuşma dahi sana yepyeni ufuklar açabilir. 🎫 Uzun lafın kısası, eğer kodların arasında kaybolmuş bir yazılımcıysan ve bir yandan da yeni insanlarla tanışıp, deneyimlerini paylaşmayı seviyorsan, Coffee Talk tam sana göre! Bu özel sohbette seni de aramızda görmekten mutluluk duyarız. ☕️🖥️ Etkinliğimizde sizleri neler bekliyor: 🧩 İlham alabileceğin sürpriz konuklarla tanışma fırsatı. 💻 İlgilendiğin alanda Networkünü genişletme fırsatı. 👥 Birlikte yeni şeyler öğrenebileceğin insanlarla tanışma fırsatı. ⚙️ Kariyer tecrübeleri anlatım odaklı sohbetlere katılma fırsatı. 👀 Unutmayın! Community Supporter Ticket alarak bu tarz etkinlikleri geliştirmemizde yardımcı olabilir ve community supporter özel avantajlarından yararlanabilirsiniz!', 'events/dmg-coffee-talk-c0769d51.png', 'multigroup', 'meetup', 'Vogs Coffee Bahariye', 'İstanbul', 0, 1695398400, 1695409200, '', 'archive', 'published', 0, '', 1035),
  ('ev-gamedev-career-meetup-081d2e1a', 'gamedev-career-meetup-081d2e1a', 'GameDev Career Meetup', 'GameDev Career Meetup Sizlerle! 📢 Tüm game development meraklılarına sesleniyoruz! Game development dünyasını keşfedeceğiniz heyecan verici bir kariyer…', 'GameDev Career Meetup Sizlerle! 📢 Tüm game development meraklılarına sesleniyoruz! Game development dünyasını keşfedeceğiniz heyecan verici bir kariyer etkinliği için bize katılmaya ne dersiniz? 📌 Sizler gibi game development meraklıları ile bağlantı kurmak, deneyimlerinizi paylaşmak ve sektörü şekillendiren en son trendler ve tekniklerin derinliklerine dalmak sizlerin elinde. İster tecrübeli bir game developer olun ister meraklı bir acemi veya sadece oyunlar konusunda tutkulu, bu etkinlik tam size göre. Networkünüzü geliştirmek, öğrenmek ve ilham almak için bu fırsatı kaçırmayın! Şimdi biletinizi alın ve etkinliğin bir parçası olun!" Etkinliğimizde sizleri neler bekliyor: 🎙️ Alanında başarılı konuşmacılar. ⚙️ Kariyer tecrübeleri anlatım odaklı oturumlar 🧩 Network''ünüzü geliştirmek için türlü etkinlikler. 🍕 Yiyecek içecek ikramı. 🎁 Sürpriz hediye ve çekilişler. 💻 İş ve staj imkanları. 👀 Unutmayın! Community Supporter Ticket alarak bu tarz etkinlikleri geliştirmemizde yardımcı olabilir ve community supporter özel avantajlarından yararlanabilirsiniz!', 'events/gamedev-career-meetup-081d2e1a.png', 'multigroup', 'meetup', 'Vogs Coffee Bahariye', 'İstanbul', 0, 1695466800, 1695481200, '', 'archive', 'published', 0, 'game development,game design,development,meetup', 1036),
  ('ev-mobil-developer-zone-0e660272', 'mobil-developer-zone-0e660272', 'Mobil Developer Zone', 'Mobile Developer Zone Yaklaşıyor! 📢 Tüm mobile developer''lara sesleniyoruz! Mobile Development''taki yenilikleri keşfedeceğiniz heyecan verici bir konferans…', 'Mobile Developer Zone Yaklaşıyor! 📢 Tüm mobile developer''lara sesleniyoruz! Mobile Development''taki yenilikleri keşfedeceğiniz heyecan verici bir konferans için bize katılmaya ne dersiniz? 📌 Sizler gibi mobile developmen meraklıları ile bağlantı kurmak, deneyimlerinizi paylaşmak ve sektörü şekillendiren en son trendler ve tekniklerin derinliklerine dalmak sizlerin elinde. İster tecrübeli bir developer olun ister meraklı bir acemi veya sadece yazılım konusunda tutkulu, bu etkinlik tam size göre. Networkünüzü geliştirmek, öğrenmek ve ilham almak için bu fırsatı kaçırmayın! Şimdi biletinizi alın ve etkinliğin bir parçası olun!" Etkinliğimizde sizleri neler bekliyor: 🎙️ Alanında başarılı konuşmacılar. ⚙️ Kariyer tecrübeleri anlatım odaklı oturumlar 🧩 Network''ünüzü geliştirmek için türlü etkinlikler. ☕️ Kahve ikramı. 🎁 Sürpriz hediye ve çekilişler. 💻 İş ve staj imkanları. 👀 Unutmayın! Community Supporter Ticket alarak bu tarz etkinlikleri geliştirmemizde yardımcı olabilir ve community supporter özel avantajlarından yararlanabilirsiniz!', 'events/mobil-developer-zone-0e660272.png', 'multigroup', 'meetup', 'İBB Zemin İstanbul', 'İstanbul', 0, 1696154400, 1696168800, '', 'archive', 'published', 0, 'android,ios,flutter,reactnative,development', 1037),
  ('ev-ml-career-hole-2023-deced6fd', 'ml-career-hole-2023-deced6fd', 'ML Career Hole 2023', 'ML Career Hole Sizlerle! 📢 Ml Career Hole bu yıl da sizlerle! Machine learning alanında önde gelen isimlerin katılımı ile heyecan verici bir konferans için…', 'ML Career Hole Sizlerle! 📢 Ml Career Hole bu yıl da sizlerle! Machine learning alanında önde gelen isimlerin katılımı ile heyecan verici bir konferans için bize katılmaya ne dersiniz? 📌 Sizler gibi machine learning meraklıları ile bağlantı kurmak, deneyimlerinizi paylaşmak ve sektörü şekillendiren en son trendler ve tekniklerin derinliklerine dalmak sizlerin elinde. İster tecrübeli bir developer olun ister meraklı bir acemi veya sadece yazılım konusunda tutkulu, bu etkinlik tam size göre. Networkünüzü geliştirmek, öğrenmek ve ilham almak için bu fırsatı kaçırmayın! Şimdi biletinizi alın ve etkinliğin bir parçası olun!" Etkinliğimizde sizleri neler bekliyor: 🎙️ Alanında başarılı konuşmacılar. ⚙️ Kariyer tecrübeleri anlatım odaklı oturumlar 🧩 Network''ünüzü geliştirmek için türlü etkinlikler. ☕️ Kahve ikramı. 🎁 Sürpriz hediye ve çekilişler. 💻 İş ve staj imkanları. 👀 Unutmayın! Community Supporter Ticket alarak bu tarz etkinlikleri geliştirmemizde yardımcı olabilir ve community supporter özel avantajlarından yararlanabilirsiniz!', 'events/ml-career-hole-2023-deced6fd.png', 'multigroup', 'meetup', 'İBB Zemin İstanbul', 'İstanbul', 0, 1698481800, 1698503400, '', 'archive', 'published', 0, '', 1038),
  ('ev-fall-dmg-game-developer-conference-03c59e91', 'fall-dmg-game-developer-conference-03c59e91', 'Fall DMG | Game Developer Conference', 'Fall DMG Sizlerle! 📢 Fall DMG, game development alanında önde gelen isimlerin katılımı ile heyecan verici bir kariyer konferansı sağlamak için sizlerle! 📌…', 'Fall DMG Sizlerle! 📢 Fall DMG, game development alanında önde gelen isimlerin katılımı ile heyecan verici bir kariyer konferansı sağlamak için sizlerle! 📌 Sizler gibi game development meraklıları ile bağlantı kurmak, deneyimlerinizi paylaşmak ve sektörü şekillendiren en son trendler ve tekniklerin derinliklerine dalmak sizlerin elinde. İster tecrübeli bir developer olun ister meraklı bir acemi veya sadece yazılım konusunda tutkulu, bu etkinlik tam size göre. Networkünüzü geliştirmek, öğrenmek ve ilham almak için bu fırsatı kaçırmayın! Şimdi biletinizi alın ve etkinliğin bir parçası olun!" 🌟 Toplulukların sizlere sağlamayı amaçladığı en büyük katkılarından biri, sizi hedeflediğiniz şirkete bir adım daha yaklaştırmaktır. Bu amaca ulaşmanıza yardımcı olmak için, Developer MultiGroup ekibi olarak, cv hazırlama süreçleri, teknik mülakatlar gibi genel anlamda büyük engeller olarak görülen konularda sizlere destek olmak istiyoruz! Cv''nizi aşağıdaki bağlantı aracılığıyla gönderdiğinizde, sizlerin içinden seçilecek katılımcılarımıza birebir teknik mülakat simülasyonuna katılma ve bu sayede kendinizi de bir mülakatta değerlendirebilme fırsatı sunuyoruz. CV Link: https://forms.gle/L8nfkPb5', 'events/fall-dmg-game-developer-conference-03c59e91.png', 'multigroup', 'conference', 'İBB Zemin İstanbul', 'İstanbul', 0, 1700991000, 1701007200, '', 'archive', 'published', 0, 'game development,gamedev,unity,unreal,Blender,Game', 1039);
INSERT OR REPLACE INTO events (id, slug, title, summary, description, cover_image, community, category, location, city, is_online, starts_at, ends_at, registration_url, source, status, is_featured, tags, sort_order) VALUES
  ('ev-dmg-coffee-talk-2-07a0fbcb', 'dmg-coffee-talk-2-07a0fbcb', 'DMG Coffee Talk #2', '🌟 Merhaba yazılım tutkunları! 🌟 📢 Developer MultiGroup, yazılıma ilgi duyan herkes için alanında önde gelen isimlerinde katılımı ile sohbet muhabbet odaklı…', '🌟 Merhaba yazılım tutkunları! 🌟 📢 Developer MultiGroup, yazılıma ilgi duyan herkes için alanında önde gelen isimlerinde katılımı ile sohbet muhabbet odaklı bir Coffee Talk duyurusu ile sizlerle! 📌 Sizler gibi yazılım meraklıları ile bağlantı kurmak, deneyimlerinizi paylaşmak, sektörü şekillendiren en son trendler ve tekniklerin derinliklerine dalmak veya sürpriz konuklar ile tanışmak sizlerin elinde. İster tecrübeli bir developer olun ister meraklı bir acemi veya sadece yazılım konusunda tutkulu, bu etkinlik tam size göre. Networkünüzü geliştirmek, öğrenmek ve ilham almak için bu fırsatı kaçırmayın! Şimdi biletinizi alın ve etkinliğin bir parçası olun! Aklınıza takılan sorular için bize ulaşabilirsiniz. Etkinliğimizde sizleri neler bekliyor: 🎙️ Alanında başarılı Konuklar. ⚙️ Kariyer tecrübeleri anlatım odaklı sohbet 🧩 Network''ünüzü geliştirmek için türlü etkinlikler. 💻 İş ve staj fırsatları yakalama şansı. 🎁 Sürpriz hediye ve çekilişler. 👀 Unutmayın! Community Supporter Ticket alarak bu tarz etkinlikleri geliştirmemizde yardımcı olabilir ve community supporter özel avantajlarından yararlanabilirsiniz!', 'events/dmg-coffee-talk-2-07a0fbcb.png', 'multigroup', 'meetup', 'Vogs Coffee Bahariye', 'İstanbul', 0, 1702724400, 1702735200, '', 'archive', 'published', 0, '', 1040),
  ('ev-webfree23-web-developer-conference-0d5e9f62', 'webfree23-web-developer-conference-0d5e9f62', 'WebFree23 | Web Developer Conference', 'WebConnect Yaklaşıyor! 📢 WebFree23, web development alanında önde gelen isimlerin katılımı ile heyecan verici bir kariyer konferansı sağlamak için sizlerle!…', 'WebConnect Yaklaşıyor! 📢 WebFree23, web development alanında önde gelen isimlerin katılımı ile heyecan verici bir kariyer konferansı sağlamak için sizlerle! 📌 Sizler gibi web development meraklıları ile bağlantı kurmak, deneyimlerinizi paylaşmak ve sektörü şekillendiren en son trendler ve tekniklerin derinliklerine dalmak sizlerin elinde. İster tecrübeli bir developer olun ister meraklı bir acemi veya sadece yazılım konusunda tutkulu, bu etkinlik tam size göre. Networkünüzü geliştirmek, öğrenmek ve ilham almak için bu fırsatı kaçırmayın! Şimdi biletinizi alın ve etkinliğin bir parçası olun!" 🌟 Toplulukların sizlere sağlamayı amaçladığı en büyük katkılarından biri, sizi hedeflediğiniz şirkete bir adım daha yaklaştırmaktır. Bu amaca ulaşmanıza yardımcı olmak için, Developer MultiGroup ekibi olarak, cv hazırlama süreçleri, teknik mülakatlar gibi genel anlamda büyük engeller olarak görülen konularda sizlere destek olmak istiyoruz! Cv''nizi aşağıdaki bağlantı aracılığıyla gönderdiğinizde, sizlerin içinden seçilecek katılımcılarımıza birebir teknik mülakat simülasyonuna katılma ve bu sayede kendinizi de bir mülakatta değerlendirebilme fırsatı sunuyoruz. CV Link: https://forms.gle/L8nfk', 'events/webfree23-web-developer-conference-0d5e9f62.png', 'multigroup', 'conference', 'Online', 'İstanbul', 0, 1703322000, 1703340000, '', 'archive', 'published', 0, 'Web Development,frontend,backend,react,angular,php,asp.net,java', 1041),
  ('ev-mobile-developer-roadmap-yeni-baslayanlar-icin-oneriler-en-iyi-ogrenme-yollari-f40cf83d', 'mobile-developer-roadmap-yeni-baslayanlar-icin-oneriler-en-iyi-ogrenme-yollari-f40cf83d', 'Mobile Developer Roadmap, Yeni başlayanlar için öneriler, En iyi Öğrenme Yolları', 'Sohbet Muhabbet geri döndü 💯 ☕️ Çayınızı kahvenizi kapıp, kafa dağıtabileceğiniz güzel bir sohbete katılmaya ne dersiniz? Haftalık gerçekleşecek bu seride her…', 'Sohbet Muhabbet geri döndü 💯 ☕️ Çayınızı kahvenizi kapıp, kafa dağıtabileceğiniz güzel bir sohbete katılmaya ne dersiniz? Haftalık gerçekleşecek bu seride her hafta farklı konuklar ile farklı konular üzerinde durup sohbet edeceğiz. 🌟 Bu hafta @kasimadalan ile Mobile Development Roadmap, Yeni başlayanlar için tavsiyeler ve bu alanda en iyi öğrenme yollarını konuşuyor olacağız! 🎁 Bize destek olmak ister misiniz? Siz de bize bir kahve ısmarlayarak destek olabilir ve bizi motive edebilirsiniz: https://www.buymeacoffee.com/MultiGroup 🧐 Sohbet muhabbetimize katılmaya ne dersiniz?', 'events/mobile-developer-roadmap-yeni-baslayanlar-icin-oneriler-en-iyi-ogrenme-yollari-f40cf83d.png', 'multigroup', 'meetup', 'Online', '', 1, 1706029200, 1706036400, '', 'archive', 'published', 0, 'android,ios,flutter,Flutter,reactnative,Agile Software Development,sohbetmuhabbet,#sohbetmuhabbet', 1042),
  ('ev-yazilimci-maas-karmasasi-ilk-isi-bulma-sorunsali-ai-bizi-issiz-birakir-mi-2287e24d', 'yazilimci-maas-karmasasi-ilk-isi-bulma-sorunsali-ai-bizi-issiz-birakir-mi-2287e24d', 'Yazılımcı maaş karmaşası, İlk işi bulma sorunsalı, AI bizi işsiz bırakır mı?', 'Sohbet Muhabbet bu haftalık konuğu ve konukları belli oldu, Çayını kahveni kap gel! 🌟 Bu hafta Yusuf Demirci ile " Yazılımcı maaş karmaşası ne durumda,…', 'Sohbet Muhabbet bu haftalık konuğu ve konukları belli oldu, Çayını kahveni kap gel! 🌟 Bu hafta Yusuf Demirci ile " Yazılımcı maaş karmaşası ne durumda, yazılımcı olarak İlk işi bulma süreçleri, AI yazılımcıları işsiz bırakır mı " gibi konular üzerinde doğacağız. 💬 Sen de bu sohbeti kendine özel kılmak istiyorsan, sormak istediğin soruları bize ilet ve konuşalım 🎁 Bize destek olmak ister misiniz? Siz de bize bir kahve ısmarlayarak destek olabilir ve bizi motive edebilirsiniz: https://www.buymeacoffee.com/MultiGroup 🧐 Sohbet muhabbetimize katılmaya ne dersiniz?', 'events/yazilimci-maas-karmasasi-ilk-isi-bulma-sorunsali-ai-bizi-issiz-birakir-mi-2287e24d.png', 'multigroup', 'meetup', 'Online', '', 1, 1706634000, 1706641200, '', 'archive', 'published', 0, 'appdevs,mobile,tech-talks,ios,android,android,ios,flutter,react,yazılım,sohbetmuhabbet', 1043),
  ('ev-apple-swift-student-challengei-kazanmaya-giden-yol-tim-cookla-tanismak-afda7049', 'apple-swift-student-challengei-kazanmaya-giden-yol-tim-cookla-tanismak-afda7049', 'Apple Swift Student Challenge’ı kazanmaya giden yol | Tim Cook’la tanışmak', '🚀 Hey Swift Geliştiricileri! Apple Swift Challenge''a hazır mısınız? 🏆 📣 BÜYÜK HABER: Geçen yılın kazananı Ömer Şanlı, bu yıl size yarışma stratejilerini ve…', '🚀 Hey Swift Geliştiricileri! Apple Swift Challenge''a hazır mısınız? 🏆 📣 BÜYÜK HABER: Geçen yılın kazananı Ömer Şanlı, bu yıl size yarışma stratejilerini ve kazanma sırlarını açıklıyor! 🌟 🎤 Sizi Neler Bekliyor? 🌐 Yarışma Stratejileri: Geçen yılın kazananı, yarışmaya nasıl yaklaştığını ve kazanma stratejilerini paylaşıyor. 💼 Proje Geliştirme İpuçları: Etkileyici projeler nasıl geliştirilir? İşte sırlar! 🧠 Mental Hazırlık: Zorluklarla nasıl başa çıkılır ve motivasyon nasıl korunur? 🎁 Ayrıca, canlı yayına katılanlara özel sürpriz hediyeler ve sorularınızı sorma şansı da sizi bekliyor! 🚀 "Geçen Yılın Şampiyonundan İlham Alın, Bu Yılın Yıldızı Siz Olun!" 🌟 Sevgili Swift geliştiricileri, bu yıl Apple Swift Challenge yarışması için daha da büyük ve etkileyici olmaya hazır mısınız? Geçen yılın zaferinden ilham alarak, Ömer Şanlı sizinle bu canlı yayında buluşuyor! 🏆 Geçen Yılın Gözünden Stratejiler: Ömer Şanlı, geçen yılın deneyimlerini paylaşacak ve sizi bu yılın zirvesine taşıyacak stratejilerini açıklayacak. Onun başarısından ilham alın, projenizi bir adım öteye taşıyın! 🚀 Yaratıcı Proje Geliştirme İpuçları: Etkileyici projelerin ardındaki sırları keşfedin. Ömer Şanlı, yarat', 'events/apple-swift-student-challengei-kazanmaya-giden-yol-tim-cookla-tanismak-afda7049.png', 'multigroup', 'meetup', 'Online', '', 1, 1707066000, 1707073200, '', 'archive', 'published', 0, '', 1044),
  ('ev-kariyerde-etkinliklerin-etkisi-alanlara-gore-maas-dagilimi-ve-daha-fazlasi-f51e4419', 'kariyerde-etkinliklerin-etkisi-alanlara-gore-maas-dagilimi-ve-daha-fazlasi-f51e4419', 'Kariyerde etkinliklerin etkisi, alanlara göre maaş dağılımı ve daha fazlası', 'Sohbet Muhabbet kartopu etkisine bağladı bile, her hafta artarak ilerleyen katılımcıları ve harika soruları ile biz çok eğleniyoruz. Aramıza katılmaya ne…', 'Sohbet Muhabbet kartopu etkisine bağladı bile, her hafta artarak ilerleyen katılımcıları ve harika soruları ile biz çok eğleniyoruz. Aramıza katılmaya ne dersiniz? 🌟 Bu hafta da Emre Hızlı ile harika konular konuşuyor olacağız. İşte bunlardan bazıları: 🍕Kariyer hayatınızda etkinliklerin etkisi 🍕Sektörde seçtiğiniz alanlara göre maaş dağılımı 🍕İlk işe girme süreçleri ve öneriler 🍕Yaptığınız işi eğlenerek yapabilecek hale getirmek için tüyolar 💬 Sen de bu sohbeti kendine özel kılmak istiyorsan, sormak istediğin soruları bize ilet ve konuşalım. 🧐 Ayrıca bu yayının bizim için geçmişten gelen güzel bir anısı var belki siz de hatırlamak istersiniz: https://twitter.com/hizliemre26/status/1619081912961605654 🎁 Bize destek olmak ister misiniz? Siz de bize bir kahve ısmarlayarak destek olabilir ve bizi motive edebilirsiniz: https://www.buymeacoffee.com/MultiGroup 🧐 Sohbet muhabbetimize katılmaya ne dersiniz?', 'events/kariyerde-etkinliklerin-etkisi-alanlara-gore-maas-dagilimi-ve-daha-fazlasi-f51e4419.png', 'multigroup', 'meetup', 'Online', '', 1, 1707498000, 1707505200, '', 'archive', 'published', 0, '', 1045),
  ('ev-yurtdisi-kariyer-yolculugu-farkli-alanlardan-yazilima-gecis-seruveni-c6c54a38', 'yurtdisi-kariyer-yolculugu-farkli-alanlardan-yazilima-gecis-seruveni-c6c54a38', 'Yurtdışı kariyer yolculuğu, Farklı alanlardan yazılıma geçiş serüveni', 'Sohbet Muhabbet bu haftalık konuğu ve konukları belli oldu, Çayını kahveni kap gel! 🌟 Bu hafta Elif Bilgin ile " Yurtdışı kariyer yolculuğu, Farklı alanlardan…', 'Sohbet Muhabbet bu haftalık konuğu ve konukları belli oldu, Çayını kahveni kap gel! 🌟 Bu hafta Elif Bilgin ile " Yurtdışı kariyer yolculuğu, Farklı alanlardan yazılıma geçiş serüveni " gibi konular üzerinde doğacağız. İşte değinmeyi planladığımız diğer konular: 🍕 Bir yazılımcının yurtdışı serüveni 🍕 Google gibi büyük bir şirkette çalışmak 🍕 Farklı bölümlerden yazılıma geçenler için öneriler ve daha fazlası 💬 Sen de bu sohbeti kendine özel kılmak istiyorsan, sormak istediğin soruları bize ilet ve konuşalım 🎁 Bize destek olmak ister misiniz? Siz de bize bir kahve ısmarlayarak destek olabilir ve bizi motive edebilirsiniz: https://www.buymeacoffee.com/MultiGroup 🧐 Sohbet muhabbetimize katılmaya ne dersiniz? Instagram Link | Twitter Link | Linkedin Link | Youtube Link | Github Link | Medium Link', 'events/yurtdisi-kariyer-yolculugu-farkli-alanlardan-yazilima-gecis-seruveni-c6c54a38.png', 'multigroup', 'meetup', 'Online', '', 1, 1707843600, 1707850800, '', 'archive', 'published', 0, '', 1046),
  ('ev-kariyer-baslangic-onerileri-yurtdisi-calisma-deneyimi-cv-nasil-olmali-8260f970', 'kariyer-baslangic-onerileri-yurtdisi-calisma-deneyimi-cv-nasil-olmali-8260f970', 'Kariyer Başlangıç Önerileri, Yurtdışı Çalışma Deneyimi, CV Nasıl Olmalı?', 'Sohbet Muhabbet bu haftalık konuğu ve konukları belli oldu, Çayını kahveni kap gel! 🌟 Bu hafta konuğumuz Wise şirketinde IOS Developer olarak çalışan Ömer…', 'Sohbet Muhabbet bu haftalık konuğu ve konukları belli oldu, Çayını kahveni kap gel! 🌟 Bu hafta konuğumuz Wise şirketinde IOS Developer olarak çalışan Ömer Ulusal değineceğimiz konular ise " Kariyer Başlangıç Önerileri, Yurtdışı Çalışma Deneyimi ve CV Nasıl Olmalı? " gibi konular üzerinde doğacağız. İşte değinmeyi planladığımız diğer konular: 🍕 Kariyerine yeni başlamış veya başlayacak olan bir developer''ın yapması mantıklı olacak hamleler 🍕 Yurtdışında çalışmak isteyen insanlar için süreç ve öneriler 🍕 Bir developer cv''si mantık olarak nasıl olmalı neler içermeli veya neler içermemeli ve daha fazlası 💬 Sen de bu sohbeti kendine özel kılmak istiyorsan, sormak istediğin soruları bize ilet ve konuşalım 🎁 Bize destek olmak ister misiniz? Siz de bize bir kahve ısmarlayarak destek olabilir ve bizi motive edebilirsiniz: https://www.buymeacoffee.com/MultiGroup 🧐 Sohbet muhabbetimize katılmaya ne dersiniz? Instagram Link | Twitter Link | Linkedin Link | Youtube Link | Github Link | Medium Link', 'events/kariyer-baslangic-onerileri-yurtdisi-calisma-deneyimi-cv-nasil-olmali-8260f970.png', 'multigroup', 'meetup', 'Online', '', 1, 1708452000, 1708459200, '', 'archive', 'published', 0, 'ıos,development,sohbetmuhabbet,kariyer', 1047),
  ('ev-sohbet-muhabbet-destek-sayfasi-e81a8f0f', 'sohbet-muhabbet-destek-sayfasi-e81a8f0f', 'Sohbet Muhabbet | Destek Sayfası', 'Sohbet Muhabbet | Destek Sayfası Metrikler [ Haftalık Güncellenmekte ] Etkinlik Sayısı: 6 Etkinlik Konuşmacı Sayısı: 7 Konuşmacı Konuşulan Konu Sayısı: 18…', 'Sohbet Muhabbet | Destek Sayfası Metrikler [ Haftalık Güncellenmekte ] Etkinlik Sayısı: 6 Etkinlik Konuşmacı Sayısı: 7 Konuşmacı Konuşulan Konu Sayısı: 18 Değinilen Konu Benzersiz Katılımcı Sayısı: 1500+ Katılımcı Toplam İzlenme: 2500+ İzlenme Toplam Süre: 10 Saat Sohbet Muhabbet | Destek Sayfası Sohbet Muhabbet sizleri sıcak bir sohbet ortamına ve harika konukları ile tanışmaya davet ediyor. Peki bu seriyi desteklemeye ne dersiniz? Unutmayın bu bir destek sayfasıdır! Bu serinin amacı, yazılım dünyasında önde gelen konukları bir araya gelerek farklı fikirlerini ve bakış açılarını keşfetmek, yeni yetenekleri ve perspektifleri desteklemek ve yazılım geliştirme alanında ilham verici sohbetlere ev sahipliği yapmaktır. Siz de bu heyecan verici yolculuğa katılmak ve bu değerli içeriğin oluşturulmasına katkıda bulunmak istemez misiniz? Destek sayfamız aracılığıyla, bilet alarak etkinliklerimize katılabilir veya sponsor olarak bu değerli serinin büyümesine yardımcı olabilirsiniz. Bilet Alarak Destek Olun: Etkinliklerimize katılmak için bilet alarak bu ve benzeri etkinlikleri geliştirmemize yardımcı olabilirsiniz Sponsor Olarak Destek Verin: Etkinliklerimizi destekleyerek sponsor olabilir v', 'events/sohbet-muhabbet-destek-sayfasi-e81a8f0f.png', 'multigroup', 'meetup', 'Online', '', 1, 1708786440, 1719345600, '', 'archive', 'published', 0, '', 1048),
  ('ev-algoritma-ve-universitenin-onemi-indie-developer-icin-marketingin-degeri-2a1b9a74', 'algoritma-ve-universitenin-onemi-indie-developer-icin-marketingin-degeri-2a1b9a74', 'Algoritma ve üniversitenin önemi?, indie developer için marketingin değeri?', 'Sohbet Muhabbet bu haftalık konuğu ve konukları belli oldu, Çayını kahveni kap gel! 🌟 Bu hafta konuğumuz Garanti BBVA Teknoloji şirketinde Senior Expert…', 'Sohbet Muhabbet bu haftalık konuğu ve konukları belli oldu, Çayını kahveni kap gel! 🌟 Bu hafta konuğumuz Garanti BBVA Teknoloji şirketinde Senior Expert Software Developer olarak çalışan Burkan Yılmaz. Değineceğimiz konular ise " Sektör için üniversite önemli mi? Algoritma bilgisinin kariyerdeki yeri, Indie developers için marketing ne kadar önemli? " gibi konular üzerinde doğacağız. İşte değinmeyi planladığımız diğer konular: 🍕 Sektör için üniversite önemli mi? İşe alımlarda üniversiteye ne kadar bakılıyor 🍕 Türkiyede "algoritma bilgisine gerek yok işe girersin" rivayeti gerçek mi? 🍕 Indie developers için marketing ne kadar önemli? Neler yapmalıyız ve daha fazlası 💬 Sen de bu sohbeti kendine özel kılmak istiyorsan, sormak istediğin soruları bize ilet ve konuşalım 🎁 Bize destek olmak ister misiniz? Siz de bize bir kahve ısmarlayarak destek olabilir ve bizi motive edebilirsiniz: 🧐 Sohbet muhabbetimize katılmaya ne dersiniz?', 'events/algoritma-ve-universitenin-onemi-indie-developer-icin-marketingin-degeri-2a1b9a74.png', 'multigroup', 'meetup', 'Online', '', 1, 1709053200, 1709060400, '', 'archive', 'published', 0, '', 1049);
